content.content:
1	@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&family=Space+Mono:wght@400;700&display=swap');
2	
3	:root {
4	  --black: #000;
5	  --white: #fff;
6	  --gray-100: #f5f5f5;
7	  --gray-200: #e0e0e0;
8	  --gray-300: #b0b0b0;
9	  --gray-400: #808080;
10	  --gray-500: #505050;
11	  --gray-600: #303030;
12	  --gray-700: #1a1a1a;
13	  --gray-800: #0a0a0a;
14	  --bg: var(--black);
15	  --fg: var(--white);
16	  --fg-dim: var(--gray-300);
17	  --fg-muted: var(--gray-400);
18	  --border: var(--gray-700);
19	  --border-subtle: var(--gray-800);
20	
21	  --space-xs: 8px;
22	  --space-sm: 16px;
23	  --space-md: 24px;
24	  --space-lg: 32px;
25	  --space-xl: 48px;
26	  --space-2xl: 64px;
27	  --space-3xl: 80px;
28	  --space-4xl: 160px;
29	}
30	
31	[data-theme="light"] {
32	  --bg: var(--white);
33	  --fg: var(--black);
34	  --fg-dim: var(--gray-600);
35	  --fg-muted: var(--gray-500);
36	  --border: var(--gray-200);
37	  --border-subtle: var(--gray-100);
38	}
39	
40	* { margin: 0; padding: 0; box-sizing: border-box; border-radius: 0; }
41	
42	html {
43	  scroll-behavior: smooth;
44	}
45	
46	body {
47	  background: var(--bg);
48	  color: var(--fg);
49	  font-family: 'Space Grotesk', sans-serif;
50	  overflow-x: hidden;
51	  -webkit-font-smoothing: antialiased;
52	  cursor: none;
53	  transition: background 0.6s ease, color 0.6s ease;
54	  font-size: 16px;
55	}
56	
57	/* FOCUS VISIBILITY (accessibility) */
58	:focus-visible {
59	  outline: 2px solid var(--fg);
60	  outline-offset: 4px;
61	}
62	
63	/* ============================================
64	   LOADING SCREEN
65	   ============================================ */
66	.loader {
67	  position: fixed;
68	  inset: 0;
69	  background: var(--black);
70	  z-index: 20000;
71	  display: flex;
72	  flex-direction: column;
73	  align-items: center;
74	  justify-content: center;
75	  transition: opacity 0.6s ease, visibility 0.6s ease;
76	}
77	.loader.done {
78	  opacity: 0;
79	  visibility: hidden;
80	}
81	.loader-logo {
82	  font-family: 'Space Mono', monospace;
83	  font-size: clamp(32px, 6vw, 48px);
84	  font-weight: 700;
85	  letter-spacing: clamp(12px, 3vw, 24px);
86	  color: var(--white);
87	  opacity: 0;
88	  animation: loaderFadeIn 0.8s ease 0.2s forwards;
89	}
90	.loader-count {
91	  font-family: 'Space Mono', monospace;
92	  font-size: 14px;
93	  color: var(--gray-500);
94	  margin-top: 24px;
95	  opacity: 0;
96	  animation: loaderFadeIn 0.4s ease 0.5s forwards;
97	}
98	.loader-bar {
99	  width: 200px;
100	  height: 1px;
101	  background: var(--gray-700);
102	  margin-top: 16px;
103	  position: relative;
104	  opacity: 0;
105	  animation: loaderFadeIn 0.4s ease 0.5s forwards;
106	}
107	.loader-bar-fill {
108	  position: absolute;
109	  left: 0;
110	  top: 0;
111	  height: 100%;
112	  width: 0%;
113	  background: var(--white);
114	  transition: width 0.1s;
115	}
116	.loader-tagline {
117	  font-family: 'Space Grotesk', sans-serif;
118	  font-size: 12px;
119	  color: var(--gray-500);
120	  margin-top: 32px;
121	  letter-spacing: 4px;
122	  text-transform: uppercase;
123	  opacity: 0;
124	  max-width: 400px;
125	  text-align: center;
126	  padding: 0 24px;
127	  animation: loaderFadeIn 0.6s ease 0.8s forwards;
128	}
129	
130	@keyframes loaderFadeIn {
131	  to { opacity: 1; }
132	}
133	
134	/* ============================================
135	   CUSTOM CURSOR SYSTEM
136	   ============================================ */
137	.cursor-main {
138	  position: fixed;
139	  width: 12px;
140	  height: 12px;
141	  background: var(--fg);
142	  pointer-events: none;
143	  z-index: 9999;
144	  mix-blend-mode: difference;
145	  transform: translate(-50%, -50%);
146	  transition: width 0.2s, height 0.2s;
147	}
148	.cursor-main.hovering {
149	  width: 40px;
150	  height: 40px;
151	}
152	
153	.cursor-follower {
154	  position: fixed;
155	  width: 40px;
156	  height: 40px;
157	  border: 1px solid var(--fg);
158	  pointer-events: none;
159	  z-index: 9998;
160	  mix-blend-mode: difference;
161	  transform: translate(-50%, -50%);
162	  opacity: 0.5;
163	  transition: opacity 0.2s;
164	}
165	.cursor-follower.hovering {
166	  width: 64px;
167	  height: 64px;
168	  opacity: 0.2;
169	}
170	
171	/* ============================================
172	   GRAIN OVERLAY
173	   ============================================ */
174	.grain-overlay {
175	  position: fixed;
176	  inset: 0;
177	  pointer-events: none;
178	  z-index: 9990;
179	  opacity: 0.04;
180	  mix-blend-mode: multiply;
181	}
182	.grain-overlay canvas {
183	  width: 100%;
184	  height: 100%;
185	  image-rendering: pixelated;
186	}
187	
188	.scanlines {
189	  position: fixed;
190	  inset: 0;
191	  pointer-events: none;
192	  z-index: 9989;
193	  opacity: 0;
194	  background: repeating-linear-gradient(
195	    0deg,
196	    transparent 0px,
197	    transparent 2px,
198	    rgba(0,0,0,0.03) 2px,
199	    rgba(0,0,0,0.03) 4px
200	  );
201	  transition: opacity 0.6s;
202	}
203	.scanlines.visible {
204	  opacity: 1;
205	}
206	
207	/* ============================================
208	   PAGE TRANSITION (clip-path)
209	   ============================================ */
210	.page-transition {
211	  position: fixed;
212	  inset: 0;
213	  background: var(--fg);
214	  z-index: 10000;
215	  clip-path: circle(0% at var(--cx, 50%) var(--cy, 50%));
216	  pointer-events: none;
217	  transition: clip-path 0.7s cubic-bezier(0.65, 0, 0.35, 1);
218	}
219	.page-transition.wiping {
220	  clip-path: circle(150% at var(--cx, 50%) var(--cy, 50%));
221	}
222	
223	/* ============================================
224	   REDUCED MOTION
225	   ============================================ */
226	@media (prefers-reduced-motion: reduce) {
227	  *, *::before, *::after {
228	    animation-duration: 0.01ms !important;
229	    animation-iteration-count: 1 !important;
230	    transition-duration: 0.01ms !important;
231	    scroll-behavior: auto !important;
232	  }
233	  .reveal, .reveal-left, .reveal-right, .reveal-scale {
234	    opacity: 1;
235	    transform: none;
236	  }
237	  .marquee { animation: none; }
238	  .cursor-main, .cursor-follower { display: none; }
239	  body { cursor: auto; }
240	}
241	
242	/* ============================================
243	   NAVIGATION
244	   ============================================ */
245	nav {
246	  position: fixed;
247	  top: 0;
248	  left: 0;
249	  right: 0;
250	  display: flex;
251	  justify-content: space-between;
252	  align-items: center;
253	  padding: 20px var(--space-3xl);
254	  z-index: 200;
255	  border-bottom: 1px solid var(--border);
256	  background: var(--bg);
257	  transition: all 0.4s ease;
258	  cursor: none;
259	}
260	
261	.logo {
262	  font-family: 'Space Mono', monospace;
263	  font-size: 18px;
264	  font-weight: 700;
265	  letter-spacing: 8px;
266	  text-transform: uppercase;
267	  color: var(--fg);
268	  text-decoration: none;
269	}
270	
271	.nav-right {
272	  display: flex;
273	  align-items: center;
274	  gap: var(--space-lg);
275	}
276	
277	.nav-links {
278	  display: flex;
279	  gap: var(--space-lg);
280	  list-style: none;
281	}
282	
283	.nav-links a {
284	  color: var(--fg-muted);
285	  text-decoration: none;
286	  font-size: 12px;
287	  letter-spacing: 3px;
288	  text-transform: uppercase;
289	  transition: color 0.2s;
290	  position: relative;
291	}
292	.nav-links a::after {
293	  content: '';
294	  position: absolute;
295	  bottom: -4px;
296	  left: 0;
297	  width: 0;
298	  height: 1px;
299	  background: var(--fg);
300	  transition: width 0.3s ease;
301	}
302	.nav-links a:hover { color: var(--fg); }
303	.nav-links a:hover::after { width: 100%; }
304	
305	.sound-toggle {
306	  background: none;
307	  border: 1px solid var(--border);
308	  color: var(--fg);
309	  padding: 8px;
310	  display: none;
311	  align-items: center;
312	  justify-content: center;
313	  cursor: pointer;
314	  transition: all 0.2s;
315	}
316	.sound-toggle:hover {
317	  background: var(--fg);
318	  color: var(--bg);
319	}
320	
321	.theme-toggle {
322	  background: none;
323	  border: 1px solid var(--border);
324	  color: var(--fg);
325	  padding: var(--space-xs) var(--space-sm);
326	  font-family: 'Space Mono', monospace;
327	  font-size: 11px;
328	  letter-spacing: 3px;
329	  text-transform: uppercase;
330	  cursor: pointer;
331	  transition: all 0.2s;
332	}
333	.theme-toggle:hover {
334	  background: var(--fg);
335	  color: var(--bg);
336	}
337	
338	.mobile-menu-btn {
339	  display: none;
340	  flex-direction: column;
341	  gap: 5px;
342	  background: none;
343	  border: 1px solid var(--border);
344	  padding: var(--space-xs);
345	  cursor: pointer;
346	}
347	.mobile-menu-btn-line {
348	  display: block;
349	  width: 20px;
350	  height: 2px;
351	  background: var(--fg);
352	  transition: transform 0.3s, opacity 0.3s;
353	}
354	.mobile-menu-btn[aria-expanded="true"] .mobile-menu-btn-line:nth-child(1) {
355	  transform: translateY(7px) rotate(45deg);
356	}
357	.mobile-menu-btn[aria-expanded="true"] .mobile-menu-btn-line:nth-child(2) {
358	  transform: translateY(-7px) rotate(-45deg);
359	}
360	
361	.mobile-menu {
362	  position: fixed;
363	  inset: 0;
364	  z-index: 10001;
365	  display: flex;
366	  align-items: flex-end;
367	  justify-content: flex-end;
368	  pointer-events: none;
369	  opacity: 0;
370	  visibility: hidden;
371	  transition: opacity 0.3s, visibility 0.3s;
372	}
373	.mobile-menu.open {
374	  pointer-events: auto;
375	  opacity: 1;
376	  visibility: visible;
377	}
378	.mobile-menu::before {
379	  content: '';
380	  position: absolute;
381	  inset: 0;
382	  background: rgba(0, 0, 0, 0.7);
383	}
384	@media (prefers-color-scheme: light) {
385	  .mobile-menu::before { background: rgba(0, 0, 0, 0.5); }
386	}
387	.mobile-menu-inner {
388	  position: relative;
389	  width: 100%;
390	  max-width: 400px;
391	  height: 100%;
392	  background: var(--bg);
393	  border-left: 1px solid var(--border);
394	  display: flex;
395	  flex-direction: column;
396	  justify-content: center;
397	  padding: var(--space-2xl) var(--space-xl);
398	  transform: translateX(100%);
399	  transition: transform 0.3s ease;
400	}
401	.mobile-menu.open .mobile-menu-inner {
402	  transform: translateX(0);
403	}
404	.mobile-menu-link {
405	  display: block;
406	  font-size: clamp(24px, 4vw, 36px);
407	  font-weight: 700;
408	  text-transform: uppercase;
409	  letter-spacing: -1px;
410	  color: var(--fg);
411	  text-decoration: none;
412	  padding: var(--space-md) 0;
413	  border-bottom: 1px solid var(--border);
414	  transition: transform 0.2s;
415	}
416	.mobile-menu-link:hover {
417	  transform: translateX(8px);
418	}
419	
420	/* ============================================
421	   SCROLL ANIMATIONS (IntersectionObserver)
422	   ============================================ */
423	.reveal {
424	  opacity: 0;
425	  transform: translateY(40px);
426	  transition: opacity 0.8s ease, transform 0.8s ease;
427	}
428	.reveal.revealed {
429	  opacity: 1;
430	  transform: translateY(0);
431	}
432	.reveal-delay-1 { transition-delay: 0.1s; }
433	.reveal-delay-2 { transition-delay: 0.2s; }
434	.reveal-delay-3 { transition-delay: 0.3s; }
435	.reveal-delay-4 { transition-delay: 0.4s; }
436	
437	.reveal-left {
438	  opacity: 0;
439	  transform: translateX(-60px);
440	  transition: opacity 0.8s ease, transform 0.8s ease;
441	}
442	.reveal-left.revealed {
443	  opacity: 1;
444	  transform: translateX(0);
445	}
446	
447	.reveal-right {
448	  opacity: 0;
449	  transform: translateX(60px);
450	  transition: opacity 0.8s ease, transform 0.8s ease;
451	}
452	.reveal-right.revealed {
453	  opacity: 1;
454	  transform: translateX(0);
455	}
456	
457	.reveal-scale {
458	  opacity: 0;
459	  transform: scale(0.9);
460	  transition: opacity 0.8s ease, transform 0.8s ease;
461	}
462	.reveal-scale.revealed {
463	  opacity: 1;
464	  transform: scale(1);
465	}
466	
467	/* ============================================
468	   HERO SECTION
469	   ============================================ */
470	.hero {
471	  min-height: 100vh;
472	  display: flex;
473	  flex-direction: column;
474	  justify-content: center;
475	  padding: 120px var(--space-3xl);
476	  position: relative;
477	  border-bottom: 1px solid var(--border);
478	  overflow: hidden;
479	}
480	
481	.hero-tag {
482	  font-family: 'Space Mono', monospace;
483	  font-size: 11px;
484	  letter-spacing: 6px;
485	  text-transform: uppercase;
486	  color: var(--fg-muted);
487	  margin-bottom: var(--space-lg);
488	  display: flex;
489	  align-items: center;
490	  gap: var(--space-sm);
491	}
492	.hero-tag::before {
493	  content: '';
494	  width: 40px;
495	  height: 1px;
496	  background: var(--fg-muted);
497	}
498	
499	.hero-title-wrap {
500	  position: relative;
501	  mix-blend-mode: difference;
502	}
503	
504	.hero-title {
505	  font-size: clamp(48px, 8vw, 120px);
506	  font-weight: 700;
507	  line-height: 0.9;
508	  letter-spacing: -2px;
509	  text-transform: uppercase;
510	  max-width: 800px;
511	  color: var(--fg);
512	}
513	.hero-title .outline {
514	  color: var(--bg);
515	  -webkit-text-stroke: 2px var(--fg);
516	  text-stroke: 2px var(--fg);
517	}
518	
519	.kinetic-letter {
520	  display: inline-block;
521	  transition: transform 0.15s ease;
522	}
523	
524	.hero-desc {
525	  max-width: 420px;
526	  margin-top: var(--space-xl);
527	  font-size: 16px;
528	  line-height: 1.6;
529	  color: var(--fg-dim);
530	  font-weight: 300;
531	}
532	
533	.hero-cta {
534	  margin-top: var(--space-2xl);
535	  display: inline-block;
536	  padding: 16px var(--space-xl);
537	  background: var(--fg);
538	  color: var(--bg);
539	  text-decoration: none;
540	  font-family: 'Space Mono', monospace;
541	  font-size: 12px;
542	  letter-spacing: 4px;
543	  text-transform: uppercase;
544	  font-weight: 700;
545	  transition: all 0.2s;
546	  border: 2px solid var(--fg);
547	}
548	.hero-cta:hover {
549	  background: var(--bg);
550	  color: var(--fg);
551	}
552	
553	/* DECORATIVE GRID */
554	.grid-overlay {
555	  position: absolute;
556	  right: var(--space-3xl);
557	  bottom: var(--space-3xl);
558	  display: grid;
559	  grid-template-columns: repeat(4, clamp(40px, 4vw, 60px));
560	  grid-template-rows: repeat(4, clamp(40px, 4vw, 60px));
561	  gap: 1px;
562	}
563	.grid-cell {
564	  border: 1px solid var(--border);
565	  background: var(--bg);
566	  transition: background 0.3s, border-color 0.3s;
567	}
568	.grid-cell.active {
569	  background: var(--fg);
570	}
571	.grid-cell:hover {
572	  border-color: var(--fg);
573	}
574	
575	/* ============================================
576	   VERTICAL TEXT ELEMENT
577	   ============================================ */
578	.vertical-text {
579	  position: absolute;
580	  font-family: 'Space Mono', monospace;
581	  font-size: 10px;
582	  letter-spacing: 6px;
583	  text-transform: uppercase;
584	  color: var(--fg-muted);
585	  opacity: 0.5;
586	}
587	.vertical-text.left {
588	  left: 20px;
589	  top: 50%;
590	  transform: rotate(-90deg);
591	  transform-origin: 0 0;
592	}
593	.vertical-text.right {
594	  right: 20px;
595	  top: 50%;
596	  transform: rotate(90deg);
597	  transform-origin: 0 0;
598	}
599	
600	/* ============================================
601	   STATEMENT SECTION
602	   ============================================ */
603	.statement {
604	  padding: var(--space-4xl) var(--space-3xl);
605	  text-align: center;
606	  position: relative;
607	  background: var(--fg);
608	  color: var(--bg);
609	}
610	
611	.statement-text {
612	  font-size: clamp(28px, 5vw, 72px);
613	  font-weight: 700;
614	  text-transform: uppercase;
615	  line-height: 1.05;
616	  letter-spacing: -2px;
617	  max-width: 1000px;
618	  margin: 0 auto;
619	  mix-blend-mode: difference;
620	  color: inherit;
621	}
622	
623	.statement-author {
624	  font-family: 'Space Mono', monospace;
625	  font-size: 11px;
626	  letter-spacing: 6px;
627	  text-transform: uppercase;
628	  color: var(--fg-muted);
629	  margin-top: var(--space-2xl);
630	}
631	
632	.quote-marks {
633	  font-size: 120px;
634	  font-family: 'Space Mono', monospace;
635	  position: absolute;
636	  top: 20px;
637	  left: var(--space-3xl);
638	  color: var(--fg);
639	  opacity: 0.1;
640	  line-height: 1;
641	}
642	
643	/* ============================================
644	   MARQUEE
645	   ============================================ */
646	.marquee-section {
647	  padding: 40px 0;
648	  border-bottom: 1px solid var(--border);
649	  overflow: hidden;
650	}
651	
652	.marquee {
653	  display: flex;
654	  gap: 48px;
655	  animation: marquee 20s linear infinite;
656	}
657	
658	@keyframes marquee {
659	  from { transform: translateX(0); }
660	  to { transform: translateX(-50%); }
661	}
662	
663	.marquee-item {
664	  font-size: clamp(36px, 6vw, 72px);
665	  font-weight: 700;
666	  text-transform: uppercase;
667	  white-space: nowrap;
668	  letter-spacing: -2px;
669	  color: var(--border);
670	}
671	.marquee-item .dot {
672	  display: inline-block;
673	  width: 12px;
674	  height: 12px;
675	  background: var(--fg);
676	  margin: 0 var(--space-lg);
677	  vertical-align: middle;
678	}
679	
680	/* ============================================
681	   STATS
682	   ============================================ */
683	.stats {
684	  display: grid;
685	  grid-template-columns: repeat(4, 1fr);
686	  background: var(--bg);
687	}
688	
689	.stat {
690	  padding: var(--space-xl) var(--space-lg);
691	  border-right: 1px solid var(--border);
692	  text-align: center;
693	  transition: background 0.3s;
694	}
695	.stat:last-child { border-right: none; }
696	.stat:hover { background: var(--gray-700); }
697	[data-theme="light"] .stat:hover { background: var(--gray-100); }
698	
699	.stat-value {
700	  font-family: 'Space Mono', monospace;
701	  font-size: clamp(32px, 4vw, 56px);
702	  font-weight: 700;
703	  letter-spacing: -2px;
704	  margin-bottom: 12px;
705	}
706	
707	.stat-label {
708	  font-size: 11px;
709	  letter-spacing: 4px;
710	  text-transform: uppercase;
711	  color: var(--fg-muted);
712	}
713	
714	/* ============================================
715	   SECTION COMMON
716	   ============================================ */
717	.section {
718	  padding: var(--space-3xl);
719	  border-bottom: 1px solid var(--border);
720	}
721	
722	.section-header {
723	  margin-bottom: var(--space-2xl);
724	  display: flex;
725	  justify-content: space-between;
726	  align-items: flex-start;
727	}
728	
729	.section-label {
730	  font-family: 'Space Mono', monospace;
731	  font-size: 11px;
732	  letter-spacing: 6px;
733	  text-transform: uppercase;
734	  color: var(--fg-muted);
735	  margin-bottom: var(--space-sm);
736	}
737	
738	.section-title {
739	  font-size: clamp(28px, 4vw, 56px);
