toolUseResult.originalFile:
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&family=Space+Mono:wght@400;700&display=swap');

:root {
  --black: #000;
  --white: #fff;
  --gray-100: #f5f5f5;
  --gray-200: #e0e0e0;
  --gray-300: #b0b0b0;
  --gray-400: #808080;
  --gray-500: #505050;
  --gray-600: #303030;
  --gray-700: #1a1a1a;
  --gray-800: #0a0a0a;
  --bg: var(--black);
  --fg: var(--white);
  --fg-dim: var(--gray-300);
  --fg-muted: var(--gray-400);
  --border: var(--gray-700);
  --border-subtle: var(--gray-800);

  --space-xs: 8px;
  --space-sm: 16px;
  --space-md: 24px;
  --space-lg: 32px;
  --space-xl: 48px;
  --space-2xl: 64px;
  --space-3xl: 80px;
  --space-4xl: 160px;
}

[data-theme="light"] {
  --bg: var(--white);
  --fg: var(--black);
  --fg-dim: var(--gray-600);
  --fg-muted: var(--gray-500);
  --border: var(--gray-200);
  --border-subtle: var(--gray-100);
}

* { margin: 0; padding: 0; box-sizing: border-box; border-radius: 0; }

html {
  scroll-behavior: smooth;
}

body {
  background: var(--bg);
  color: var(--fg);
  font-family: 'Space Grotesk', sans-serif;
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
  cursor: none;
  transition: background 0.6s ease, color 0.6s ease;
  font-size: 16px;
}

/* FOCUS VISIBILITY (accessibility) */
:focus-visible {
  outline: 2px solid var(--fg);
  outline-offset: 4px;
}

/* ============================================
   LOADING SCREEN
   ============================================ */
.loader {
  position: fixed;
  inset: 0;
  background: var(--black);
  z-index: 20000;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  transition: opacity 0.6s ease, visibility 0.6s ease;
}
.loader.done {
  opacity: 0;
  visibility: hidden;
}
.loader-logo {
  font-family: 'Space Mono', monospace;
  font-size: clamp(32px, 6vw, 48px);
  font-weight: 700;
  letter-spacing: clamp(12px, 3vw, 24px);
  color: var(--white);
  opacity: 0;
  animation: loaderFadeIn 0.8s ease 0.2s forwards;
}
.loader-count {
  font-family: 'Space Mono', monospace;
  font-size: 14px;
  color: var(--gray-500);
  margin-top: 24px;
  opacity: 0;
  animation: loaderFadeIn 0.4s ease 0.5s forwards;
}
.loader-bar {
  width: 200px;
  height: 1px;
  background: var(--gray-700);
  margin-top: 16px;
  position: relative;
  opacity: 0;
  animation: loaderFadeIn 0.4s ease 0.5s forwards;
}
.loader-bar-fill {
  position: absolute;
  left: 0;
  top: 0;
  height: 100%;
  width: 0%;
  background: var(--white);
  transition: width 0.1s;
}
.loader-tagline {
  font-family: 'Space Grotesk', sans-serif;
  font-size: 12px;
  color: var(--gray-500);
  margin-top: 32px;
  letter-spacing: 4px;
  text-transform: uppercase;
  opacity: 0;
  max-width: 400px;
  text-align: center;
  padding: 0 24px;
  animation: loaderFadeIn 0.6s ease 0.8s forwards;
}

@keyframes loaderFadeIn {
  to { opacity: 1; }
}

/* ============================================
   CUSTOM CURSOR SYSTEM
   ============================================ */
.cursor-main {
  position: fixed;
  width: 12px;
  height: 12px;
  background: var(--fg);
  pointer-events: none;
  z-index: 9999;
  mix-blend-mode: difference;
  transform: translate(-50%, -50%);
  transition: width 0.2s, height 0.2s;
}
.cursor-main.hovering {
  width: 40px;
  height: 40px;
}

.cursor-follower {
  position: fixed;
  width: 40px;
  height: 40px;
  border: 1px solid var(--fg);
  pointer-events: none;
  z-index: 9998;
  mix-blend-mode: difference;
  transform: translate(-50%, -50%);
  opacity: 0.5;
  transition: opacity 0.2s;
}
.cursor-follower.hovering {
  width: 64px;
  height: 64px;
  opacity: 0.2;
}

/* ============================================
   GRAIN OVERLAY
   ============================================ */
.grain-overlay {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9990;
  opacity: 0.04;
  mix-blend-mode: multiply;
}
.grain-overlay canvas {
  width: 100%;
  height: 100%;
  image-rendering: pixelated;
}

.scanlines {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9989;
  opacity: 0;
  background: repeating-linear-gradient(
    0deg,
    transparent 0px,
    transparent 2px,
    rgba(0,0,0,0.03) 2px,
    rgba(0,0,0,0.03) 4px
  );
  transition: opacity 0.6s;
}
.scanlines.visible {
  opacity: 1;
}

/* ============================================
   PAGE TRANSITION (clip-path)
   ============================================ */
.page-transition {
  position: fixed;
  inset: 0;
  background: var(--fg);
  z-index: 10000;
  clip-path: circle(0% at var(--cx, 50%) var(--cy, 50%));
  pointer-events: none;
  transition: clip-path 0.7s cubic-bezier(0.65, 0, 0.35, 1);
}
.page-transition.wiping {
  clip-path: circle(150% at var(--cx, 50%) var(--cy, 50%));
}

/* ============================================
   REDUCED MOTION
   ============================================ */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
  .reveal, .reveal-left, .reveal-right, .reveal-scale {
    opacity: 1;
    transform: none;
  }
  .marquee { animation: none; }
  .cursor-main, .cursor-follower { display: none; }
  body { cursor: auto; }
}

@media (hover: none) {
  .cursor-main, .cursor-follower { display: none; }
  body { cursor: auto; }
  nav, .work-item, .gallery-item, form { cursor: auto; }
}

@media (prefers-color-scheme: light) {
  :root:not([data-theme]) {
    --bg: var(--white);
    --fg: var(--black);
    --fg-dim: var(--gray-600);
    --fg-muted: var(--gray-500);
    --border: var(--gray-200);
    --border-subtle: var(--gray-100);
  }
}

/* ============================================
   NAVIGATION
   ============================================ */
nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 20px var(--space-3xl);
  z-index: 200;
  border-bottom: 1px solid var(--border);
  background: var(--bg);
  transition: all 0.4s ease;
  cursor: none;
}

.logo {
  font-family: 'Space Mono', monospace;
  font-size: 18px;
  font-weight: 700;
  letter-spacing: 8px;
  text-transform: uppercase;
  color: var(--fg);
  text-decoration: none;
}

.nav-right {
  display: flex;
  align-items: center;
  gap: var(--space-lg);
}

.nav-links {
  display: flex;
  gap: var(--space-lg);
  list-style: none;
}

.nav-links a {
  color: var(--fg-muted);
  text-decoration: none;
  font-size: 12px;
  letter-spacing: 3px;
  text-transform: uppercase;
  transition: color 0.2s;
  position: relative;
}
.nav-links a::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  width: 0;
  height: 1px;
  background: var(--fg);
  transition: width 0.3s ease;
}
.nav-links a:hover { color: var(--fg); }
.nav-links a:hover::after { width: 100%; }

.sound-toggle {
  background: none;
  border: 1px solid var(--border);
  color: var(--fg);
  padding: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  transition: all 0.2s;
}
.sound-toggle:hover {
  background: var(--fg);
  color: var(--bg);
}

.theme-toggle {
  background: none;
  border: 1px solid var(--border);
  color: var(--fg);
  padding: var(--space-xs) var(--space-sm);
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  letter-spacing: 3px;
  text-transform: uppercase;
  cursor: pointer;
  transition: all 0.2s;
}
.theme-toggle:hover {
  background: var(--fg);
  color: var(--bg);
}

.mobile-menu-btn {
  display: none;
  flex-direction: column;
  gap: 5px;
  background: none;
  border: 1px solid var(--border);
  padding: var(--space-xs);
  cursor: pointer;
}
.mobile-menu-btn-line {
  display: block;
  width: 20px;
  height: 2px;
  background: var(--fg);
  transition: transform 0.3s, opacity 0.3s;
}
.mobile-menu-btn[aria-expanded="true"] .mobile-menu-btn-line:nth-child(1) {
  transform: translateY(7px) rotate(45deg);
}
.mobile-menu-btn[aria-expanded="true"] .mobile-menu-btn-line:nth-child(2) {
  transform: translateY(-7px) rotate(-45deg);
}

.mobile-menu {
  position: fixed;
  inset: 0;
  z-index: 10001;
  display: flex;
  align-items: flex-end;
  justify-content: flex-end;
  pointer-events: none;
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.3s, visibility 0.3s;
}
.mobile-menu.open {
  pointer-events: auto;
  opacity: 1;
  visibility: visible;
}
.mobile-menu::before {
  content: '';
  position: absolute;
  inset: 0;
  background: rgba(0, 0, 0, 0.7);
}
@media (prefers-color-scheme: light) {
  .mobile-menu::before { background: rgba(0, 0, 0, 0.5); }
}
.mobile-menu-inner {
  position: relative;
  width: 100%;
  max-width: 400px;
  height: 100%;
  background: var(--bg);
  border-left: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: var(--space-2xl) var(--space-xl);
  transform: translateX(100%);
  transition: transform 0.3s ease;
}
.mobile-menu.open .mobile-menu-inner {
  transform: translateX(0);
}
.mobile-menu-link {
  display: block;
  font-size: clamp(24px, 4vw, 36px);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: -1px;
  color: var(--fg);
  text-decoration: none;
  padding: var(--space-md) 0;
  border-bottom: 1px solid var(--border);
  transition: transform 0.2s;
}
.mobile-menu-link:hover {
  transform: translateX(8px);
}

/* ============================================
   SCROLL ANIMATIONS (IntersectionObserver)
   ============================================ */
.reveal {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s ease, transform 0.8s ease;
}
.reveal.revealed {
  opacity: 1;
  transform: translateY(0);
}
.reveal-delay-1 { transition-delay: 0.1s; }
.reveal-delay-2 { transition-delay: 0.2s; }
.reveal-delay-3 { transition-delay: 0.3s; }
.reveal-delay-4 { transition-delay: 0.4s; }

.reveal-left {
  opacity: 0;
  transform: translateX(-60px);
  transition: opacity 0.8s ease, transform 0.8s ease;
}
.reveal-left.revealed {
  opacity: 1;
  transform: translateX(0);
}

.reveal-right {
  opacity: 0;
  transform: translateX(60px);
  transition: opacity 0.8s ease, transform 0.8s ease;
}
.reveal-right.revealed {
  opacity: 1;
  transform: translateX(0);
}

.reveal-scale {
  opacity: 0;
  transform: scale(0.9);
  transition: opacity 0.8s ease, transform 0.8s ease;
}
.reveal-scale.revealed {
  opacity: 1;
  transform: scale(1);
}

/* ============================================
   HERO SECTION
   ============================================ */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  padding: 120px var(--space-3xl);
  position: relative;
  border-bottom: 1px solid var(--border);
  overflow: hidden;
}

.hero-tag {
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  letter-spacing: 6px;
  text-transform: uppercase;
  color: var(--fg-muted);
  margin-bottom: var(--space-lg);
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}
.hero-tag::before {
  content: '';
  width: 40px;
  height: 1px;
  background: var(--fg-muted);
}

.hero-title-wrap {
  position: relative;
  mix-blend-mode: difference;
}

.hero-title {
  font-size: clamp(48px, 8vw, 120px);
  font-weight: 700;
  line-height: 0.9;
  letter-spacing: -2px;
  text-transform: uppercase;
  max-width: 800px;
  color: var(--fg);
}
.hero-title .outline {
  color: var(--bg);
  -webkit-text-stroke: 2px var(--fg);
  text-stroke: 2px var(--fg);
}

.kinetic-letter {
  display: inline-block;
  transition: transform 0.15s ease;
}

.hero-desc {
  max-width: 420px;
  margin-top: var(--space-xl);
  font-size: 16px;
  line-height: 1.6;
  color: var(--fg-dim);
  font-weight: 300;
}

.hero-cta {
  margin-top: var(--space-2xl);
  display: inline-block;
  padding: 16px var(--space-xl);
  background: var(--fg);
  color: var(--bg);
  text-decoration: none;
  font-family: 'Space Mono', monospace;
  font-size: 12px;
  letter-spacing: 4px;
  text-transform: uppercase;
  font-weight: 700;
  transition: all 0.2s;
  border: 2px solid var(--fg);
}
.hero-cta:hover {
  background: var(--bg);
  color: var(--fg);
}

/* DECORATIVE GRID */
.grid-overlay {
  position: absolute;
  right: var(--space-3xl);
  bottom: var(--space-3xl);
  display: grid;
  grid-template-columns: repeat(4, clamp(40px, 4vw, 60px));
  grid-template-rows: repeat(4, clamp(40px, 4vw, 60px));
  gap: 1px;
}
.grid-cell {
  border: 1px solid var(--border);
  background: var(--bg);
  transition: background 0.3s, border-color 0.3s;
}
.grid-cell.active {
  background: var(--fg);
}
.grid-cell:hover {
  border-color: var(--fg);
}

/* ============================================
   VERTICAL TEXT ELEMENT
   ============================================ */
.vertical-text {
  position: absolute;
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  letter-spacing: 6px;
  text-transform: uppercase;
  color: var(--fg-muted);
  opacity: 0.5;
}
.vertical-text.left {
  left: 20px;
  top: 50%;
  transform: rotate(-90deg);
  transform-origin: 0 0;
}
.vertical-text.right {
  right: 20px;
  top: 50%;
  transform: rotate(90deg);
  transform-origin: 0 0;
}

/* ============================================
   STATEMENT SECTION
   ============================================ */
.statement {
  padding: var(--space-4xl) var(--space-3xl);
  text-align: center;
  position: relative;
  background: var(--fg);
  color: var(--bg);
}

.statement-text {
  font-size: clamp(28px, 5vw, 72px);
  font-weight: 700;
  text-transform: uppercase;
  line-height: 1.05;
  letter-spacing: -2px;
  max-width: 1000px;
  margin: 0 auto;
  mix-blend-mode: difference;
  color: inherit;
}

.statement-author {
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  letter-spacing: 6px;
  text-transform: uppercase;
  color: var(--fg-muted);
  margin-top: var(--space-2xl);
}

.quote-marks {
  font-size: 120px;
  font-family: 'Space Mono', monospace;
  position: absolute;
  top: 20px;
  left: var(--space-3xl);
  color: var(--fg);
  opacity: 0.1;
  line-height: 1;
}

/* ============================================
   MARQUEE
   ============================================ */
.marquee-section {
  padding: 40px 0;
  border-bottom: 1px solid var(--border);
  overflow: hidden;
}

.marquee {
  display: flex;
  gap: 48px;
  animation: marquee 20s linear infinite;
}

@keyframes marquee {
  from { transform: translateX(0); }
  to { transform: translateX(-50%); }
}

.marquee-item {
  font-size: clamp(36px, 6vw, 72px);
  font-weight: 700;
  text-transform: uppercase;
  white-space: nowrap;
  letter-spacing: -2px;
  color: var(--border);
}
.marquee-item .dot {
  display: inline-block;
  width: 12px;
  height: 12px;
  background: var(--fg);
  margin: 0 var(--space-lg);
  vertical-align: middle;
}

/* ============================================
   STATS
   ============================================ */
.stats {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  background: var(--bg);
}

.stat {
  padding: var(--space-xl) var(--space-lg);
  border-right: 1px solid var(--border);
  text-align: center;
  transition: background 0.3s;
}
.stat:last-child { border-right: none; }
.stat:hover { background: var(--gray-700); }
[data-theme="light"] .stat:hover { background: var(--gray-100); }

.stat-value {
  font-family: 'Space Mono', monospace;
  font-size: clamp(32px, 4vw, 56px);
  font-weight: 700;
  letter-spacing: -2px;
  margin-bottom: 12px;
}

.stat-label {
  font-size: 11px;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: var(--fg-muted);
}

/* ============================================
   SECTION COMMON
   ============================================ */
.section {
  padding: var(--space-3xl);
  border-bottom: 1px solid var(--border);
}

.section-header {
  margin-bottom: var(--space-2xl);
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
}

.section-label {
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  letter-spacing: 6px;
  text-transform: uppercase;
  color: var(--fg-muted);
  margin-bottom: var(--space-sm);
}

.section-title {
  font-size: clamp(28px, 4vw, 56px);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: -2px;
}

.section-count {
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  color: var(--fg-muted);
  letter-spacing: 2px;
}

/* ============================================
   MANIFESTO SECTION
   ============================================ */
.manifesto {
  padding: var(--space-4xl) var(--space-3xl);
  position: relative;
  border-bottom: 1px solid var(--border);
}

.manifesto-content {
  max-width: 900px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-2xl);
}

.manifesto-text {
  font-size: 16px;
  line-height: 1.8;
  color: var(--fg-dim);
  font-weight: 300;
}

.manifesto-text p {
  margin-bottom: var(--space-md);
}

.manifesto-text strong {
  color: var(--fg);
  font-weight: 600;
}

.manifesto-rules {
  padding-top: 8px;
}

.manifesto-rule {
  font-family: 'Space Mono', monospace;
  font-size: 13px;
  letter-spacing: 2px;
  color: var(--fg-muted);
  padding: var(--space-sm) 0;
  border-bottom: 1px solid var(--border);
  display: flex;
  justify-content: space-between;
  align-items: center;
  transition: all 0.3s;
}
.manifesto-rule:hover {
  color: var(--fg);
  padding-left: 12px;
}
.manifesto-rule:first-child {
  border-top: 1px solid var(--border);
}

/* ============================================
   FEATURES / PRINCIPLES
   ============================================ */
.features {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1px;
  background: var(--border);
}

.feature {
  padding: var(--space-xl);
  background: var(--bg);
  transition: background 0.3s, color 0.3s;
  position: relative;
  overflow: hidden;
  cursor: pointer;
}
.feature::before {
  content: '';
  position: absolute;
  inset: 0;
  background: var(--fg);
  transform: translateY(100%);
  transition: transform 0.4s ease;
  z-index: 0;
}
.feature:hover::before {
  transform: translateY(0%);
}
.feature:hover {
  color: var(--bg);
}
.feature > * {
  position: relative;
  z-index: 1;
}

.feature-number {
  font-family: 'Space Mono', monospace;
  font-size: clamp(48px, 5vw, 72px);
  font-weight: 700;
  color: var(--border);
  line-height: 1;
  margin-bottom: var(--space-lg);
  transition: color 0.3s;
}
.feature:hover .feature-number {
  color: var(--fg);
}

.feature-title {
  font-size: clamp(16px, 1.5vw, 20px);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: var(--space-md);
}

.feature-desc {
  font-size: 14px;
  line-height: 1.7;
  color: var(--fg-dim);
  font-weight: 300;
  transition: color 0.3s;
}
.feature:hover .feature-desc {
  color: var(--fg);
}

/* ============================================
   WORK/PROJECTS
   ============================================ */
.work-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1px;
  background: var(--border);
}

.work-item {
  aspect-ratio: 4/3;
  background: var(--bg);
  position: relative;
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  padding: var(--space-lg);
  overflow: hidden;
  cursor: pointer;
  transition: background 0.3s;
  border: none;
  color: inherit;
  text-align: left;
  font-family: inherit;
}
.work-item:hover { background: var(--gray-600); }

.work-preview {
  position: absolute;
  inset: var(--space-lg);
  bottom: 100px;
  overflow: hidden;
  opacity: 0;
  transition: opacity 0.4s ease;
}
.work-item:hover .work-preview { opacity: 1; }

.work-preview-inner {
  width: 100%;
  height: 100%;
  background: var(--gray-600);
  overflow: hidden;
}
[data-theme="light"] .work-preview-inner { background: var(--gray-100); }

.work-preview-grid {
  width: 100%;
  height: 100%;
  background-size: 20px 20px;
  background-image:
    linear-gradient(to right, var(--bg) 1px, transparent 1px),
    linear-gradient(to bottom, var(--bg) 1px, transparent 1px);
  opacity: 0.2;
}

.work-year {
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  color: var(--fg-muted);
  margin-bottom: 8px;
}

.work-title {
  font-size: clamp(20px, 2.5vw, 28px);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: -1px;
}

.work-tag {
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  color: var(--fg-muted);
  margin-top: 8px;
  letter-spacing: 3px;
  text-transform: uppercase;
}

.work-num {
  position: absolute;
  top: var(--space-lg);
  right: var(--space-lg);
  font-family: 'Space Mono', monospace;
  font-size: clamp(40px, 5vw, 64px);
  font-weight: 700;
  color: var(--border);
  transition: color 0.3s;
}
.work-item:hover .work-num { color: var(--fg); }

/* ============================================
   GALLERY
   ============================================ */
.gallery {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  background: var(--border);
  gap: 1px;
}

.gallery-item {
  aspect-ratio: 1;
  background: var(--bg);
  position: relative;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.3s;
  cursor: pointer;
  border: none;
  color: inherit;
  font-family: inherit;
  padding: 0;
}
.gallery-item:hover { background: var(--gray-600); }

.gallery-pattern {
  position: absolute;
  inset: 0;
  transition: opacity 0.3s;
}
.gallery-item:hover .gallery-pattern { opacity: 0.3; }

.gallery-item:nth-child(1) .gallery-pattern {
  background: repeating-linear-gradient(0deg, var(--fg) 0px, var(--fg) 2px, transparent 2px, transparent 12px);
  opacity: 0.15;
}
.gallery-item:nth-child(2) .gallery-pattern {
  background: repeating-linear-gradient(45deg, var(--fg) 0px, var(--fg) 1px, transparent 1px, transparent 8px);
  opacity: 0.15;
}
.gallery-item:nth-child(3) .gallery-pattern {
  background: repeating-conic-gradient(var(--fg) 0% 25%, transparent 25% 50%) 0 0 / 30px 30px;
  opacity: 0.1;
}
.gallery-item:nth-child(4) .gallery-pattern {
  background: repeating-linear-gradient(90deg, var(--fg) 0px, var(--fg) 2px, transparent 2px, transparent 6px);
  opacity: 0.15;
}

.gallery-label {
  position: relative;
  z-index: 1;
  font-family: 'Space Mono', monospace;
  font-size: 11px;
  letter-spacing: 6px;
  text-transform: uppercase;
  padding: 12px 24px;
  background: var(--bg);
  border: 1px solid var(--fg);
  color: var(--fg);
  transition: all 0.3s;
}
.gallery-item:hover .gallery-label {
  background: var(--fg);
  color: var(--bg);
}

/* ============================================
   TEAM SECTION
   ============================================ */
.team-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 1px;
  background: var(--border);
}

.team-member {
  background: var(--bg);
  padding: var(--space-lg);
  text-align: center;
  transition: background 0.3s;
  position: relative;
  overflow: hidden;
  cursor: pointer;
}
.team-member:hover { background: var(--gray-600); }

.team-portrait {
  width: 100%;
  aspect-ratio: 1;
  margin-bottom: var(--space-md);
  position: relative;
  overflow: hidden;
}

.portrait-placeholder {
  width: 100%;
  height: 100%;
  background: var(--gray-700);
  transition: transform 0.4s ease;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: clamp(32px, 4vw, 48px);
  font-weight: 700;
  font-family: 'Space Mono', monospace;
  color: var(--fg);
  opacity: 0.3;
}
[data-theme="light"] .portrait-placeholder { background: var(--gray-100); opacity: 0.5; }
.team-member:hover .portrait-placeholder { transform: scale(1.05); }

.team-name {
  font-size: clamp(14px, 1.2vw, 16px);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: 8px;
}

.team-role {
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: var(--fg-muted);
}

/* ============================================
   TIMELINE
   ============================================ */
.timeline {
  position: relative;
  padding-left: var(--space-3xl);
}

.timeline::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 1px;
  background: var(--border);
}

.timeline-item {
  position: relative;
  padding: var(--space-xl) 0;
  border-bottom: 1px solid var(--border);
}
.timeline-item:last-child { border-bottom: none; }
.timeline-item::before {
  content: '';
  position: absolute;
  left: calc(var(--space-3xl) * -1 + 7px);
  top: 56px;
  width: 8px;
  height: 8px;
  background: var(--fg);
  transition: transform 0.2s;
}
.timeline-item:hover::before {
  transform: scale(1.5);
}

.timeline-year {
  font-family: 'Space Mono', monospace;
  font-size: clamp(32px, 4vw, 48px);
  font-weight: 700;
  margin-bottom: var(--space-sm);
}

.timeline-title {
  font-size: clamp(18px, 2vw, 24px);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 2px;
  margin-bottom: var(--space-sm);
}

.timeline-desc {
  font-size: 14px;
  color: var(--fg-dim);
  line-height: 1.6;
  max-width: 600px;
}

/* ============================================
   CONTACT SECTION
   ============================================ */
#contact {
  padding: var(--space-3xl);
  border-top: 1px solid var(--border);
}

.contact-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-2xl);
  margin-top: var(--space-2xl);
}

.contact-info {
  display: flex;
  flex-direction: column;
  gap: var(--space-lg);
}

.contact-info-item h4 {
  font-size: 11px;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: var(--fg-muted);
  margin-bottom: 8px;
  font-weight: 500;
}

.contact-info-item a,
.contact-info-item p {
  color: var(--fg-dim);
  text-decoration: none;
  font-size: 16px;
  transition: color 0.2s;
}
.contact-info-item a:hover {
  color: var(--fg);
}

.contact-form {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
}

.form-group {
  position: relative;
}

.form-group label {
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: var(--fg-muted);
  display: block;
  margin-bottom: 8px;
}

.form-group input,
.form-group textarea {
  width: 100%;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--fg);
  padding: 14px 16px;
  font-family: 'Space Grotesk', sans-serif;
  font-size: 14px;
  transition: border-color 0.2s;
  outline: none;
  cursor: none;
}
.form-group input:focus,
.form-group textarea:focus {
  border-color: var(--fg);
}

.form-group textarea {
  resize: vertical;
  min-height: 120px;
}

.form-submit {
  align-self: flex-start;
  padding: 14px var(--space-xl);
  background: var(--fg);
  color: var(--bg);
  border: 2px solid var(--fg);
  font-family: 'Space Mono', monospace;
  font-size: 12px;
  letter-spacing: 4px;
  text-transform: uppercase;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.2s;
}
.form-submit:hover {
  background: var(--bg);
  color: var(--fg);
}

.form-success {
  font-family: 'Space Mono', monospace;
  font-size: 12px;
  color: var(--fg-muted);
  letter-spacing: 2px;
  text-transform: uppercase;
  opacity: 0;
  transition: opacity 0.3s;
  text-align: center;
}
.form-success.visible {
  opacity: 1;
}

/* ============================================
   PROJECT MODAL
   ============================================ */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.9);
  z-index: 5000;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  visibility: hidden;
  transition: opacity 0.4s, visibility 0.4s;
}
.modal-overlay.active {
  opacity: 1;
  visibility: visible;
}

.modal-content {
  background: var(--bg);
  color: var(--fg);
  border: 1px solid var(--border);
  max-width: 800px;
  width: 90%;
  max-height: 80vh;
  overflow-y: auto;
  position: relative;
  transform: translateY(20px) scale(0.97);
  transition: transform 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
}
.modal-overlay.active .modal-content {
  transform: translateY(0) scale(1);
}

.modal-close {
  position: absolute;
  top: 20px;
  right: 20px;
  width: 40px;
  height: 40px;
  background: transparent;
  border: 1px solid var(--border);
  color: var(--fg);
  font-size: 18px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
  z-index: 1;
}
.modal-close:hover {
  background: var(--fg);
  color: var(--bg);
}

.modal-header {
  padding: var(--space-2xl) var(--space-2xl) var(--space-lg);
  border-bottom: 1px solid var(--border);
}

.modal-header-meta {
  display: flex;
  gap: var(--space-md);
  margin-bottom: var(--space-sm);
}

.modal-header-meta span {
  font-family: 'Space Mono', monospace;
  font-size: 10px;
  letter-spacing: 3px;
  text-transform: uppercase;
  color: var(--fg-muted);
}

.modal-header h2 {
  font-size: clamp(28px, 3vw, 36px);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: -2px;
}

.modal-preview {
  height: clamp(150px, 20vh, 250px);
  position: relative;
  overflow: hidden;
}

.work-card-pattern {
  position: absolute;
  inset: 0;
  opacity: 0.1;
}
.work-card-pattern.pattern-1 {
  background:
    repeating-linear-gradient(0deg, var(--fg) 0px, var(--fg) 1px, transparent 1px, transparent 24px),
    repeating-linear-gradient(90deg, var(--fg) 0px, var(--fg) 1px, transparent 1px, transparent 24px);
}
.work-card-pattern.pattern-2 {
  background:
    repeating-conic-gradient(var(--fg) 0% 25%, transparent 25% 50%) 0 0 / 40px 40px;
}
.work-card-pattern.pattern-3 {
  background:
    repeating-linear-gradient(45deg, var(--fg) 0px, var(--fg) 1px, transparent 1px, transparent 16px);
}
.work-card-pattern.pattern-4 {
  background:
    radial-gradient(circle at 10px 10px, var(--fg) 1px, transparent 1px) 0 0 / 20px 20px;
}

.modal-body {
  padding: var(--space-lg) var(--space-2xl) var(--space-2xl);
}

.modal-body p {
  font-size: 15px;
  line-height: 1.8;
  color: var(--fg-dim);
  font-weight: 300;
  margin-bottom: var(--space-sm);
}

.modal-body ul {
  list-style: none;
  padding: 0;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--space-sm);
  margin-top: var(--space-md);
}

.modal-body ul li {
  font-size: 13px;
  color: var(--fg-muted);
  padding: 12px 16px;
  border: 1px solid var(--border);
  letter-spacing: 1px;
}

/* ============================================
   FOOTER
   ============================================ */
.footer-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-2xl);
}

.footer-brand {
  font-family: 'Space Mono', monospace;
  font-size: clamp(20px, 2vw, 24px);
  letter-spacing: 8px;
  text-transform: uppercase;
  margin-bottom: 20px;
}

.footer-copy {
  font-size: 13px;
  color: var(--fg-muted);
  font-weight: 300;
  line-height: 1.6;
}

.footer-col-title {
  font-size: 11px;
  letter-spacing: 4px;
  text-transform: uppercase;
  color: var(--fg-muted);
  margin-bottom: 20px;
  font-weight: 500;
}

.footer-links {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.footer-links a {
  color: var(--fg-dim);
  text-decoration: none;
  font-size: 14px;
  transition: color 0.2s;
}
.footer-links a:hover { color: var(--fg); }

/* ============================================
   RESPONSIVE
   ============================================ */
@media (max-width: 1024px) {
  .gallery { grid-template-columns: repeat(2, 1fr); }
  .team-grid { grid-template-columns: repeat(2, 1fr); }
}

@media (max-width: 768px) {
  .hero { padding: 120px var(--space-md); }
  .section { padding: 64px var(--space-md); }
  .manifesto { padding: 80px var(--space-md); }
  .manifesto-content { grid-template-columns: 1fr; gap: var(--space-lg); }
  .features { grid-template-columns: 1fr; }
  .stats { grid-template-columns: repeat(2, 1fr); }
  .gallery { grid-template-columns: 1fr 1fr; }
  .work-grid { grid-template-columns: 1fr; }
  .team-grid { grid-template-columns: 1fr 1fr; }
  .contact-grid { grid-template-columns: 1fr; gap: var(--space-2xl); }
  #contact { padding: 48px var(--space-md); }
  nav { padding: 16px var(--space-md); }
  .nav-links { display: none; }
  .cursor-main, .cursor-follower { display: none; }
  body { cursor: auto; }
  .statement { padding: 80px var(--space-md); }
  .statement-text { font-size: 28px; }
  .modal-header { padding: var(--space-lg) var(--space-md) var(--space-sm); }
  .modal-body { padding: var(--space-md); }
  .modal-body ul { grid-template-columns: 1fr; }
  .footer-grid { grid-template-columns: 1fr; gap: var(--space-lg); }
  .grid-overlay { right: var(--space-md); bottom: var(--space-md); }
}

@media (max-width: 480px) {
  .stats { grid-template-columns: 1fr 1fr; }
  .gallery { grid-template-columns: 1fr; }
  .team-grid { grid-template-columns: 1fr; }
}

